INSERT INTO `esami_questions` VALUES (1,1,'GENERAL','Il raffreddamento delle apparecchiature del SMTS viene effettuato con aria raffreddata proveniente da:','Dal pacco SX del gruppo condizionamento velivolo','Dal pacco DX del gruppo condizionamento velivolo','Da entrambi i pacchi','Tutte le risposte sono esatte','B'),(2,1,'GENERAL','Estraendo la SMTS Handle si verifica che:','La Manual Control Valve si chiude e l\'inserto posto all\'interno della \"mixing chamber \" si apre','La Manual Control Valve e l\'inserto posto all\'interno della \"mixing chamber \" si aprono contemporaneamente','La manual Control Valve si apre e l\'inserto si chiude','*******************','C'),(3,1,'GENERAL','Quali sono i valori di tensione nominali in corrente continua ed alternata a 400 Hz applicate ai carichi SMTS:','24/28 VDC; 115 VAC monofase;','28 VDC; 115 VAC monofase; 220/400 VAC trifase','24/28 VDC; 200 VAC monofase; 115/200 VAC trifase','*******************','A'),(4,1,'GENERAL','Quanti inverter sono installati nel Sistema di missione per alimentare le apparecchiature del SMTS','Un inverter monofase e due trifase','Due inverter monofasi e due trifase','Dopo aggiornamento sistema ATOS non ci sono più inverter','Dopo l\'aggiornamento dei sistemi (anno 2020) un solo inverter','D'),(5,1,'FARO','L\'escursione in elevation del faro rispetto al proprio asse é:','da 0 a -50°','da +5° a -50°','da 0° a -60°','*******************','B'),(6,1,'APPARATI RADIO','Quale di queste frequenze è quella di guardia del sistema in mod. VHF/AM','121.800 MHZ','121.500 MHZ','128.500 kHZ','*******************','B'),(7,1,'APPARATI RADIO','Al termine della prodecura di test della radio V/UFH AM-FM la luce \"FAIL\" in caso di malfunzione:','Resta accesa','Continua a lampeggiare','Si spegne','*******************','A'),(8,1,'GENERAL','Il ricevitore HF e la sua antenna Tuning Unit si trovano:','Dietro il pannello posteriore del vano cargo posteriore','Nel Rack Apparati','Sotto il pavimento della cabina passeggeri in posizione baricentrica','Dietro alla postazione del Captain','A'),(9,1,'GENERAL','Con il pulsante HF dell\'Audio Control Panel della MOC1 inserito cosa avviene se agisco sullo switch INT/RAD','Predispongo la HF per la trasmissione SATCOMM','Si Trasmette sulla frequenza che il TACCO ha impostato sulla radio.','Si Trasmette sulla frequenza che il CAPTAIN ha impostato sulla radio.','*******************','C'),(10,1,'GENERAL','Se il pulsante VFM1 dell\'Audio Control Panel del Tavolo Tattico è inserito cosa accade.','Il tacco Trasmette in caso di emergenza con la radio VHF AM del CM1','Il tacco predispone in caso di emergenza  la radio VHF AM del CM1, per il controllo dell\'operatore della MOC1','Il tacco Trasmette  con la radio VHF della MOC1','Il tacco Trasmette  con la radio U/VHF della MOC1','C'),(11,1,'GENERAL','Se il pulsante VFM2 dell\'Audio Control Panel della MOC2 è inserito e successivamente premo  il pulsante VU3 su quali radio trasmetto ?','Nessuna perchè sul ACP della MOC2 non c\'è il pulsante VU3 (radio U/VHF solo MOC1)','Possono trasmettere sia con la  VHF della MOC1 sia con la UHF della MOC1','Possono trasmettere sia con la  VHF della MOC2 sia con la UHF della MOC1','Posso Trasmettere con la radio V/UHF del SMTS','D'),(12,1,'EOST','Con quale comando si riposiziona la torretta in posizione di riposo','HOLD','STOW','CAGE','*******************','B'),(13,1,'EOST','Quanti e quali sono le focali che si possono impostare sul sensore EON','TRE (21-75-243)','QUATTRO (600-1200-1900-3200)','TRE (600-1200-3200)','A FOCALE CONTINUA DA 9 A 162','B'),(14,1,'EOST','Quali sono le focali che possiamo usare con il sensore IR dellaWESCAM 20','21-75-243','9-162','600-1200-1900-3200','tutte le risposte sono errate','D'),(15,1,'TACTICAL','Quanti USER MARKER possiamo inserire sulla tactical Situation','10','50','100','*******************','C'),(16,1,'RADAR','Dove è ubicato il RTP del Radar Gabbiano ULTS80 ?','Rack Apparati','Sotto il pavimento vicino alla botola ATM','MOC 1','Sotto in pavimento vicino al sedile della MOC1','D'),(17,1,'GENERAL','A cosa serve l\'Auto Parallel Switch ?','A commutare l\' HF da modalità Radio a DL','A connettere la Work Station (moc1)  al Mission Computer della Moc1','A connettere le Work Station al Mission Computer.','Ha connettere la stampante alle WorkStation del SMTS','D'),(18,1,'GENERAL','Dove è ubicata la Analog Video Switch (AVS)','Rack Apparati','Rack Ausiliario','Una nella Moc1 e una nella  Moc2','Moc1','D'),(19,1,'GENERAL','Dove è ubicato il \"Interface Unit\"  (IFU) ?','Moc1','Moc1 - Moc 2 (c\'è ne sono due una per Moc)','Rack Apparati','*******************','A'),(20,1,'GENERAL','Dove è ubicato il Contol Panel del faro di ricerca?','Moc1','Console Comunication','Rack Ausiliario','Observer di dx','B'),(21,1,'APPARATI RADIO','A cosa serve anche se non utilizzabile lo Switching Unit  Control Panel ?','A trasformare i segnali digitali del\' EOST in analogico da inviare al faro di ricerca','Ad interfacciare il SMTS con il radar SLAR','A selezionare le modalità di funzionamento delle radio HF e V/UHF (moc1)','Tutte le risposte sono errate','C'),(22,1,'RADAR','Al fine di avere una buona immagine ISAR occorre','Mare grosso e angolo di aspetto perpendicolare alla prua del velivolo','Mare calmo e angolo di aspetto sui 40 ° rispetto alla prua del velivolo','Mare grosso e angolo di aspetto sui 40° rispetto al fascio radar.','Le risposte B-C sono esatte','C'),(23,1,'GENERAL','Qual\'è la funzione del TDO ?','Alimentare il Mission Computer','Alimentare i carichi sensibili alle Power interruption ed è collegato alla batteria','Alimentare i carichi sensibili alle Power interruption ed è collegato alla batteria di emergenza','Tutte le risposte sono errate','C'),(24,1,'GENERAL','Se va in avaria in GEN 1 del velivolo cosa accade.','Il SMTS rimane acceso perchè il TDO mantiene il carico per il tempo necessario a spegnere il sistema','Il SMTS in automatico spegne tutti i computer in modo da non danneggiarli','Viene a mancare l\'alimentazione del SMTS','*******************','C'),(25,1,'GENERAL','Il pulsante CNT SMOKE in cabina di pilotaggio se messo in ON','Abilita i 3 rilevatori di fumi in cabina','Abilita i 4 rilevatori di fumi in cabina e apre la Manual Control Valve','Abilita i 4 rilevatori di fumi in cabina e chiude la Manual Control Valve','Tutte le risposte sono errate','D'),(26,1,'GENERAL','Quanti container del tipo omologato per ATR 42 si possono imbarcare in configurazione CARGO','9','8','Nessuno per mancanza di omologazione','*******************','A'),(27,1,'GENERAL','Qual è la pubblicazione di Maricogecap di riferimento per il personale E.F.V. della linea ATR 42','AER 103 ED OTT 2019','AER 103 ED SETT 2013','AER 102 ED SETT 2013','**','B'),(28,1,'GENERAL','A bordo del velivolo ATR 42 MP chi è il responsabile della condotta del velivolo','Pilota con il grado più alto','Mission Commander','Pilota  la qualifica più elevata a bordo','*','C'),(29,1,'GENERAL','Dove siede a bordo del velivolo ATR 42 il CM1','A destra','A sinistra','Tavolo Tattico','*','B'),(30,1,'GENERAL','Dove siede a bordo del velivolo ATR 42 il CM2','A destra','A sinistra','Tavolo Tattico','*','A'),(31,1,'GENERAL','Quante ore di volo deve effettuare un operatore pronto impiego per mantenere la qualifica','80 annuali','35 per semestre','70 annuali','*','B'),(32,1,'GENERAL','Dopo quanto tempo di inattività un operatore pronto impiego perde la qualifica','1 mese','2 mesi','3 mesi','*','B'),(33,1,'RADAR','La massima scala selezionabile in modalità SRV è','160 Nm','80 Nm','40 Nm','*******************','A'),(34,1,'GENERAL','Quanti paracadutisti Si potrebbero imbarcare sul velivolo ATR 42 MP','27','36','48','*******************','A'),(35,1,'GENERAL','Quanti passeggeri si possono imbarcare al massimo sul velivolo ATR 42 MP in configurazione trasporto passeggeri','42','48','46','***','B'),(36,1,'FARO','Il Faro di ricerca è alimentato dalla:','Lo STATIC INV 3 PH','TRU','TDO','********','B'),(37,1,'FARO','L\'energia elettrica necessaria per alimentare la lampada ad elevata intensità del faro di ricerca viene prelevata dalla:','28 VDC MAIN BUS 1','28VDC HOT MAIN BATT BUS','115/200 VAC MAIN BUS 1','********','C'),(38,1,'FARO','Gli interruttori a posizione momentanea \"START\", installati sia sulla manual control box che sul pannello di controllo della consolle (COC), hanno la funzione di:','Avviare il sistema faro di ricerca ed i relativi circuiti di controllo','Innescare l\'accensione della lampada del faro','Inizializzare l\'asservimento del faro alla telecamera sulla torretta EOST','********','B'),(39,1,'FARO','La calibrazione del faro di ricarca deve essere effettuata:','Con sistema di missione operativo e prima del primo volo della giornata','Dopo la rimozione/installazione del faro di ricerca e/o della torretta EOST e/o delle scatole di controllo e/o dei rispettivi circuiti di interconnessione','Ad ogni primo volo della giornata dopo il decollo e con sistema di missione già operativo','********','B'),(40,1,'GENERAL','Sulla MOC 1 la spia OVER TEMP MOC#1 del quadretto di comando EDU #1 si accende :','Quando la temperatura dell\'aria in uscita dalla consolle MOC 1  supera i 45 ° C.','Dopo circa 10 sec. da quando sono state ripristinate le normali condizioni di raffreddamento del sistema SMTS','Quando la temperatura dell\'aria in uscita dalla consolle MOC 1  supera i 55 ° C.','Le risposte B e C sono esatte','C'),(41,1,'GENERAL','Sul quadretto di comando EDU # 1 installato sulla MOC 1, l\'accensione della spia FAULT sul pulsante COOLING FAN avviene in caso di:','Disagree tra il comando e la posizione reale della OVERBOARD VALVE','Forzatura in posizione di chiusura della OVERBOARD VALVE','Avaria del ventilatore di estrazione dell\'aria o dei circuiti elettrici a lui annessi','********','C'),(42,1,'GENERAL','Con velivolo a terra e sistema SMTS operativo, posizionando l\'interruttore OVBD VALVE su CL ci si predispone per :','Chiudere completamente la OVERBOARD VALVE per trattenere l\'aria estratta dalle consolles e dal rack apparati all\'interno del velivolo','Controllare l\'apertura di questa valvola in modo manuale e quindi parzializzare la luce di scarico dell\'aria verso l\'esterno','Aprire completamente la valvola per scaricare rapidamente a terra tutta l\'aria estratta dal sistema SMTS','********','A'),(43,1,'GENERAL','Sul quadretto di comando EDU # 1 installato sulla MOC 1, l\'accensione della spia SMOKE indica che:','All\'interno della MOC 1 (la consolle prioritaria per l\'operatività del sistema SMTS) vi è presenza di fumo','Nella zona della cabina passeggeri, dove sono installate le consolles, la presenza di fumo ha attivato gli SMOKE DETECTORS del cielo cabina','Nel condotto di estrazione dell\'aria vi è presenza di fumo','********','C'),(44,1,'GENERAL','Lo STATIC INV 1 PH alimenta:','Stampante','Radar','Faro di ricerca','********','A'),(45,1,'GENERAL','L\'alimentazione elettrica dei carichi SMTS viene effettuato tramite dei quadretti di comando così dislocati:','Uno in cabina di pilotaggio sulla consolle laterale Sx ed un altro sul Rack Apparati','Uno sulla MOC 1, uno sulla MOC 2 ed uno sulla COC.','Uno in cabina di pilotaggio sulla consolle laterale Dx ed un altro sulla MOC 1','********','C'),(46,1,'GENERAL','Sui quadretti di comando dell\'alimentazione elettrica del sistema SMTS sono installati due interruttori denominati MASTER SW (2P) e PWR(EDU1) ON/OFF la cui funzione singolarmente è di:','Consentire il collegamento/scollegamento dei carichi SMTS in DC','Consentire il collegamento/scollegamento dei carichi SMTS in DC e contemporaneamente mantenere lo stato di carica della batteria che è collegata sulla barra di emergenza','Consentire il collegamento/scollegamento dei carichi SMTS solo in AC','Le risposte A e C sono esatte','A'),(47,1,'GENERAL','Gli interruttori MASTER SW e SMTS PWR ON/OFF sono dotati ciascuno di due spie inglobate nel pulsante di comando e denominate rispettivamente SHED ed OFF. L\'indicazione SHED sul pulsante MASTER PWR ON/OFF DEL 2° P è accesa nelle seguenti condizioni:','Quando il pulsante MASTER SW viene selezionato OFF','Quando entrambi gli interruttori vengono selezionati OFF','Quando il pulsante MASTER SW viene selezionato ON ed il pulsante PWR ON/OFF viene selezionato OFF','Tutte le risposte sono errate','C'),(48,1,'APPARATI RADIO','Il Captain può utilizzare la radio HF per contattare la C.O. di Roma','Si Sempre perchè il control Panel della Radio HF è ubicata in cabina di pilotaggio','No perchè la gestione della RADIO HF è di competenza dell\'Operatore di Volo','Si, solo però se la spia DL sul miscellaneus Control panel in cabina di pilotaggio non sia accesa.','Si, solo però se la spia AVAIL sul miscellaneus Control panel in cabina di pilotaggio  sia spenta.','C'),(49,1,'GENERAL','Dove sono ubicate le scatole nere del velivolo','Coda velivolo non accessibili per sicurezza','Coda velivolo accessibili tramite uno sportelli','Cargo vicino alla batteria in modo da essere sempre alimentati','*','B'),(50,1,'RADAR','Il tasto rapido F4 a cosa serve','Ad inizializzare una traccia radar','A selezionare lo zoom radar','A cambiare la scala','Ad effettuare l\'ON TOP','A'),(51,1,'EOST','Può accadere che la posizione del velivolo che leggiamo sullla situazione tattica sia diversa da quella che leggiamo sul monitor sensori (eost).','No perché è sepre quella che viene dal FMS e GPS','Si solo sé va in avaria il GPS','Si','**','C'),(52,1,'GENERAL','A cosa serve il comando rapido F9','Ad inizializzare una traccia radar','A marcare l\'on top','A registrare il video EOST','**','C'),(53,1,'EOST','Lo switch \"VIC\" del Hand Control dell\'Eost serve.','A variare l\'algoritmo del AVT','Premendo verso l\'alto a selezionare il sensore da visionare','a selezionare la modalità Filter SPA On/Off','Tutte le risposte sono errate','B'),(54,1,'EOST','A cosa serve il tasto \"Geo Focus\" dell\'Hand Control dell\'Eost','Ad attivare/disattivare Auto focus','Ad attivare e disattivare il laser','A selezioanre i POI','**','A'),(55,1,'GENERAL','Come si attivata ELT - Emergency Locator Trasmitter','A contatto con l\'acqua e con una accellerazione > 1 g','Dal pilota','con accellerazione superiore a 5 g','*','C'),(56,1,'GENERAL','Qual è la differenza tra MANTA 1 e MANTA 2','Nessuna sono tutte e 2 dei 400','Nessuna sono tutte e 2 dei 500','il M1 è un 400 il M2 è un 500','il M1 è un 500 il M2 è un 400','C'),(57,1,'GENERAL','Il radar SLAR su che velivolo è installato','Su tutti i velivoli','Solo su Manta 1','E installato sul Manta 2 e sul Manta 1','E\' installato sul Manta 2 e sul Manta 3','C'),(58,1,'GENERAL','L\'apparato ATM è imbarcato sul Manta 3.','vero','E installato sul Manta 2 e sul Manta 1','E\' installato sul Manta 2 e sul Manta 3','****','C'),(59,1,'SATCOMM','Dove è ubicato il sistema satellitare SDU 7320','moc1','coc','rack apparati in basso','rack apparati in alto','D'),(60,1,'AIS','Dove è ubicato il sistema AIS','MOC1','MOC2','rack apparati in alto','rack apparati in basso','D'),(61,1,'SATCOMM','Dove è ubicato High Power Amplifier HPA-7450 del sistema satcomm','moc1','cielo cabina sotto l\'antenna','rack apparati','**','C'),(62,1,'SATCOMM','Come si attiva il telefono satellitare','Quando accendiamo un motore avendo così la DC di un generatore','Quando attiviamo il sistema di missione','Devo selezionare POWER ON nella Vcu del SATCOMM','Devo selezionare la connessione background nella vcu del Satcomm','C'),(63,1,'AIS','Come mi accorgo se arriva un mesaggio AIS','Non posso ricevere messaggi perché Maricogeap ha inibito questa funzione','Viene visulaizzato in verde una indicazione di AIS MSG in basso a sinistra vicino al pulsante status','Sul tattico viene mostrato un messaggio \"msg AIS\"','**','B'),(64,1,'AIS','Posso inviare dei brevi messaggi con il sistema AIS verso altre stazioni AIS','Non posso ricevere messaggi perché Maricogeap ha inibito questa funzione','Si ma devo attivare la funzione TX ON nella finestra active mode','Si basta selezionare il destinatario e premere il pulsante SEND','*','B'),(65,1,'GENERAL','Dove è ubicato lo Switch Gbit','MOC1','Rack Apparati','Rack Ausiliario','**','B'),(66,1,'GENERAL','Dove è ubicato il Radar Maintenance Panel','MOC1','Rack Apparati in basso vicino al Ricetrasmettitore','Console Comunication','**','C'),(67,1,'GENERAL','Dove è ubicato il Digital Master Control Unit (DMCU)','MOC1','Rack Apparati in basso','Console Comunication','**','C'),(68,1,'GENERAL','Dove è ubicata la Video Audio Encoder (VAE)','MOC1','Rack Apparati in basso','onsole Comunication','**','C'),(69,1,'GENERAL','Posso cambiare l\'identificativo della missione \"set id\" se ho attivo lo SLAR','SI','NO','**','**','B'),(70,1,'TACTICAL','Tramite la HCU della wescam 20 l si possono registrare le immagini presentati sul monitor sensori in formato analogico.','NO','Si, premendo il PUSH BUTTON frontale sinistro nero','Sì, premendo il PUSH BUTTON frontale destro rosso','*','A'),(71,1,'TACTICAL','Di che colore è il piano di volo attivo?','Rosso','Verde','Bianco','*','C'),(72,1,'TACTICAL','Si può  modificare un piano di volo attivo?','No','Sì, ma dopo averlo acquisito selezionando \"Load Curr\" nel Mission Planing e rinviato al FMS','Sì, ma dopo averlo acquisito selezionando \"New\" nel Mission Planing e rinviato al FMS','*','B'),(73,1,'TACTICAL','Il pilota può visualizzare le coordinate del piano di volo impostato dal Sistema di Missione ?','No','Sì, solo dopo che l\'operatore ha selezionato la funzione nel Mission Planing TO FMS','Sì, solo se  su una delle MOC è abilitata la funzione FLAT DISPLAY','*','B'),(74,1,'TACTICAL','Quante sono le modalità di presentazione delle mappe di navigazione sulla Situazione Tattica?','2','3','4','*','B'),(75,1,'TACTICAL','In quale modalità di presentazione il simbolo del velivolo si muove all interno della Mappa?','North Oriented','Heading Oriented','North Fixed Oriented','*','C'),(76,1,'TACTICAL','Che cosa è E/O LOS?','La Slant Range del Radar','IL  punto di intersezione con il terreno del sensore elettroottico','IL Bearing del DF','*','B'),(77,1,'TACTICAL','Quali sono i parametri visualizzati dal Measure Tool ?','Solo il RANGE','Solo il BEARING e il TTG','RANGE E BEARING','*','C'),(78,1,'TACTICAL','Si possono visualizzare i dati caratteristici (lat-Long etc) di un target Radar sulla Situazione Tattica?','no','Sì, sempre','Sì, solo dopo averlo selezionato','*','C'),(79,1,'TACTICAL','Quali sono i dati che fornisce la funzione di Cursor Reporting ?','La posizione geografica (Lat, Lon) del velivolo','La posizione geografica dei target','La posizione geografica del cursore','*','C'),(80,1,'TACTICAL','Cosa permette di effettuare la funzione SET ID?','di settare i dati del piano di volo','di inserire o modificare un identificativo della missione','di visualizzare la Lat, Long  del coursor Reporting','*','B'),(81,1,'GENERAL','Quando generalmente, in condizioni standard, si procede alla procedura di attivazione del S.M.T.S.','Durante le manovre di rullaggio, in modo di avere il sistema operativo subito dopo il decollo.','dopo l\' after take off check list a descrizione del Captain','Dopo la messa in moto di entrambi i velivoli in modo che possiamo raffreddare il S.M.T.S.','*','B'),(82,1,'GENERAL','Quando generalmente in condizioni standard si procede allo spegnimento del S.M.T.S.','A discrezione del CAPTAIN, prima delle manovre di atterraggio.','Con il velivolo al parcheggio, prima di spegnere il motore dx','Durante le fasi di rullaggio per poter scaricare dal data base i dati di missione','*','A'),(83,1,'GENERAL','In condizioni normali dopo quando tempo la spia fault del pulsante cooling fan si spegna dopo averlo messo in posizione di on.','Essendo una spia di FAULT, dopo aver eliminato l\'avaria.','Dopo circa 2 minuti','Dopo circa 3 minutii','*','B'),(84,1,'TACTICAL','Dalla postazione della MOC 1  si può visionare la quota BAROMETRICA del velivolo','Sulla titolazione delle immagini video dei sensori se abilitati con il pulsante frontale nero dell\'Hand 