  KEY `class_id` (`class_id`),
  CONSTRAINT `esami_students_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `utenti` (`id`) ON DELETE CASCADE,
  CONSTRAINT `esami_students_ibfk_2` FOREIGN KEY (`class_id`) REFERENCES `esami_classes` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
